import React, { useState, useEffect } from 'react';
import { Text, View, Button } from 'react-native';
import NetInfo from '@react-native-community/netinfo';
import AsyncStorage from '@react-native-async-storage/async-storage';

const App = () => {
  const [networkStatus, setNetworkStatus] = useState(null);

  useEffect(() => {
    NetInfo.addEventListener('connectionChange', (state) => {
      setNetworkStatus(state.isConnected ? 'connected' : 'disconnected');
    });
  }, []);

  const logNetworkRequest = (url, method, headers, body) => {
    console.debug(`Network Request: ${url}`, { method, headers, body });
  };

  const logAsyncStorageOperation = (key, value) => {
    console.debug(`Async Storage Operation: ${key}`, value);
  };

  const logUserAction = (action) => {
    console.debug(`User Action: ${action}`);
  };

  const logStateChange = (prevState, nextState) => {
    console.debug('State Change:', { prevState, nextState });
  };

  const logAuthenticationToken = (token) => {
    console.debug('Authentication Token:', token);
  };

  const logUserData = (data) => {
    console.debug('User Data:', data);
  };

  const logApiResponse = (response) => {
    console.debug('API Response:', response);
  };

  return (
    <View>
      <Text>Network Status: {networkStatus}</Text>
      <Button title="Log Network Request" onPress={() => logNetworkRequest('api.example.com', 'GET', {}, null)} />
      <Button title="Log Async Storage Operation" onPress={() => logAsyncStorageOperation('token', 'abcdefg')} />
      <Button title="Log User Action" onPress={() => logUserAction('Clicked Button')} />
      <Button title="Log State Change" onPress={() => logStateChange({ count: 0 }, { count: 1 })} />
      <Button title="Log Authentication Token" onPress={() => logAuthenticationToken('token123456789')} />
      <Button title="Log User Data" onPress={() => logUserData({ name: 'John Doe', email: 'johndoe@example.com' })} />
      <Button title="Log API Response" onPress={() => logApiResponse({ statusCode: 200, data: { message: 'Success' } })} />
    </View>
  );
};

export default App;